UPDATE top_chef_candidats SET parcours = 'Baptiste Lecaplain est un humoriste et acteur français, né le 23 mai 1985 à Avranches (Manche).', lien_wikipedia = 'https://fr.wikipedia.org/?curid=5123990', notes_source = 'wikidata:Q2883665' WHERE nom_complet = 'Arnaud Baptiste';
UPDATE top_chef_candidats SET parcours = 'Arnaud Delvenne, né le 24 juillet 1985, est un chef cuisinier belge, chef de son propre restaurant Nono, ouvert à Liège en mars 2022. Il est finaliste de la treizième saison de Top Chef, diffusée en 2022 sur M6 en France et RTL-TVI en Belgique et est le premier candidat belge à accéder à la grande finale depuis les débuts du concours.', lien_wikipedia = 'https://fr.wikipedia.org/?curid=15035410', notes_source = 'wikidata:Q112566792' WHERE nom_complet = 'Arnaud Delvenne';
UPDATE top_chef_candidats SET parcours = 'Arnaud De Lie, né le 16 mars 2002 à Libramont, est un coureur cycliste belge, membre de l''équipe Lotto.', lien_wikipedia = 'https://fr.wikipedia.org/?curid=14620226', notes_source = 'wikidata:Q105503507' WHERE nom_complet = 'Arnaud Munster';
UPDATE top_chef_candidats SET parcours = 'La onzième saison de Top Chef, est une émission de télévision franco-belge de téléréalité culinaire, diffusée chaque semaine sur M6 du mercredi 19 février 2020 au mercredi 17 juin 2020 et sur RTL-TVI du lundi 24 février 2020 au lundi 22 juin 2020. Elle est animée par Stéphane Rotenberg. Cette édition est remportée par David Gallienne qui empoche 56 410 €, proportionnellement au pourcentage des points obtenus pour son menu lors de la finale (56,41 %). Il l''emporte au terme de 10 h de cuisine face à Adrien Cachot qui a lui obtenu 43,59 % des points.', lien_wikipedia = 'https://fr.wikipedia.org/?curid=12743406', notes_source = 'wikidata:Q86667440' WHERE nom_complet = 'Arthur Vonderheyden';
