UPDATE top_chef_candidats SET parcours = 'Baptiste Renouard, né le 18 septembre 1991 à Fontainebleau (Seine-et-Marne) est un chef cuisinier français, dont le restaurant Ochre, à Rueil-Malmaison, est étoilé au guide Michelin depuis 2021. Il participe à la dixième saison de Top Chef, diffusée sur M6 et RTL TVI en 2019.', lien_wikipedia = 'https://fr.wikipedia.org/?curid=14663709', notes_source = 'wikidata:Q110779163' WHERE nom_complet = 'Baptiste Renouard';
