UPDATE top_chef_candidats SET parcours = 'Camille Delcroix, né le 11 novembre 1989 à Saint-Saulve (Nord) est un chef cuisinier français. Il est le gagnant de la saison 9 de Top Chef diffusée sur M6 en 2018. Ancien second de cuisine du château de Beaulieu, à Busnes, restaurant double-étoilé Michelin de Marc Meurin, il est depuis décembre 2021 chef de son propre restaurant, le Bacôve, à Saint-Omer (Pas-de-Calais), une étoile Michelin en mars 2024.', lien_wikipedia = 'https://fr.wikipedia.org/?curid=12779997', notes_source = 'wikidata:Q68596060' WHERE nom_complet = 'Camille Delcroix';
