UPDATE top_chef_candidats SET parcours = 'La deuxième saison de Top Chef, émission de télévision franco-belge de télé-réalité culinaire, a été diffusée sur M6 et sur RTL-TVI du 31 janvier 2011 au 4 avril 2011. Elle a été animée par Stéphane Rotenberg et Agathe Lecaron. Stéphanie Le Quellec (28 ans) a remporté cette édition et les 100 000 €. Tiffany Depardieu a quant à elle gagné le prix de Top Chef du web et remporte 10 000 €.', lien_wikipedia = 'https://fr.wikipedia.org/?curid=5225319', notes_source = 'wikidata:Q3468606' WHERE nom_complet = 'Ronan Kernen';
UPDATE top_chef_candidats SET parcours = 'La cinquième saison de Top Chef, émission de télévision franco-belge de télé-réalité culinaire est diffusée sur M6 et sur RTL-TVI à partir du 20 janvier 2014 et jusqu''au 21 avril 2014. Elle est animée par Stéphane Rotenberg. Pierre Augé (34 ans) a remporté cette édition et 62 480 €.', lien_wikipedia = 'https://fr.wikipedia.org/?curid=7655211', notes_source = 'wikidata:Q16510010' WHERE nom_complet = 'Ruben Sarfati';
UPDATE top_chef_candidats SET parcours = 'Samuel Albert, né le 20 septembre 1988 à Soucelles (Maine-et-Loire), est un chef cuisinier français. Gagnant de la saison 10 de Top Chef diffusée sur M6 en 2019, alors qu''il est chef exécutif de l''ambassade de Belgique au Japon, il est depuis novembre 2019 chef du restaurant Les Petits Prés et, depuis 2023, chef de la brasserie du ralliement à Angers. En 2023, il participe à la saison Top Chef: World All-Stars de l''émission originale Top Chef, diffusée sur la chaîne américaine Bravo et la chaîne Gulli en France.', lien_wikipedia = 'https://fr.wikipedia.org/?curid=12777839', notes_source = 'wikidata:Q68596742' WHERE nom_complet = 'Samuel Albert';
UPDATE top_chef_candidats SET parcours = 'La septième saison de Top Chef, émission de télévision franco-belge de téléréalité culinaire est diffusée sur M6 et sur RTL-TVI du 25 janvier au 18 avril 2016. Elle est animée par Stéphane Rotenberg. Le second de cuisine Xavier Pincemin a remporté cette édition et 52 500 €.', lien_wikipedia = 'https://fr.wikipedia.org/?curid=9721746', notes_source = 'wikidata:Q24929195' WHERE nom_complet = 'Sarah Gade';
UPDATE top_chef_candidats SET parcours = 'Sarah Mainguy, née le 11 août 1994 à Nogent-sur-Marne (Val-de-Marne), est une cheffe cuisinière française, installée à Nantes, à la tête des cuisines du restaurant étoilé Freia. Elle est finaliste de la saison 12 de Top Chef, diffusée sur M6 et RTL TVI en 2021. Elle est désignée « Jeune talent » par le Gault et Millau, édition 2022.', lien_wikipedia = 'https://fr.wikipedia.org/?curid=14184133', notes_source = 'wikidata:Q109043939' WHERE nom_complet = 'Sarah Mainguy';
