UPDATE top_chef_candidats SET parcours = 'La dixième saison de Top Chef, est une émission de télévision franco-belge de téléréalité culinaire, diffusée sur M6 du 6 février 2019 au 8 mai 2019 et sur RTL-TVI du 11 février 2019 au 13 mai 2019. Elle est animée par Stéphane Rotenberg. Cette édition est remportée par Samuel Albert qui empoche 53 080 €, proportionnellement au pourcentage des points obtenus pour son menu lors de la finale (53,08 %). Il l''emporte au terme de 10 h de cuisine face à Guillaume Pape qui a lui obtenu 46,92 % des points.', lien_wikipedia = 'https://fr.wikipedia.org/?curid=12338721', notes_source = 'wikidata:Q65158944' WHERE nom_complet = 'Sébastien Oger';
