UPDATE top_chef_candidats SET parcours = 'Stéphanie Le Quellec, née Lecocq le 6 décembre 1981 à Enghien-les-Bains (Val-d''Oise) est une chef cuisinière française doublement étoilée. Elle est vainqueur de la saison 2 de Top Chef sur M6 en 2011. Elle est une des rares femmes à avoir obtenu deux étoiles au guide Michelin.', lien_wikipedia = 'https://fr.wikipedia.org/?curid=12575403', notes_source = 'wikidata:Q33104183' WHERE nom_complet = 'Stéphanie Le Quellec';
