UPDATE top_chef_candidats SET parcours = 'Tabata Mey, née Rainho Goncalves le 10 février 1978 à Rio de Janeiro (Brésil) est une cheffe cuisinière brésilienne. Depuis 2024, elle est cheffe du restaurant Ombellule à Lyon, avec son mari Ludovic Mey, une étoile Michelin depuis 2025., Son restaurant précédent, Les Apothicaires, avait déjà été étoilé. Tabata Mey s''est fait connaître du grand public sous le nom de Tabata Bonardi (nom d''épouse issu de son premier mariage) lors de la saison 3 de Top Chef, diffusée sur M6 en 2012, où elle a été demi-finaliste. Elle a été également « la première femme que Paul Bocuse désigne à la tête de l''un de ses établissements ».', lien_wikipedia = 'https://fr.wikipedia.org/?curid=12207353', notes_source = 'wikidata:Q60834656' WHERE nom_complet = 'Tabata Bonardi';
